SELECT DISTINCT m.description, m.mechanism_type
FROM mechanisms m
JOIN compounds c ON c.mechanism = m.mechanism_id;

SELECT mechanism_id, description, mechanism_type
FROM mechanisms
WHERE mechanism_type = 'Inhibition';

SELECT team_id, team_name
FROM research_teams
ORDER BY team_name ASC;

SELECT *
FROM compounds
WHERE created_by = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT compounds.name, mechanisms.description
FROM compounds
JOIN mechanisms ON compounds.mechanism = mechanisms.mechanism_id;

SELECT mechanism, mechanism_count, RANK() OVER (ORDER BY mechanism_count DESC) AS rank
FROM (
    SELECT mechanism, COUNT(*) AS mechanism_count
    FROM compounds
    GROUP BY mechanism
) AS MechanismCounts;

SELECT compound_id, COUNT(DISTINCT user_id) AS num_users_accessed 
FROM user_access_logs
GROUP BY compound_id;
